//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:검색->관리부서 , 2:검색->거래처
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (select_code, txtCode, txtName, sPopupCls) {
  let sCmdName = "";
  let pWhere;
  let code, name;
  code = txtCode.getValue();
  if (txtName == null) {
    name = "";
  } else {
    name = txtName.getValue();
  }
  switch (select_code) {
    //유형
    case '1':
      sCmdName = "retrieveNonledgerAsetPatternCdInfo";
      udc_goodsCd.setSelectId(sCmdName);
      udc_goodsCd.cfCommonPopUp(scwin.udc_goodsCd_callbackfunc, code, name, sPopupCls, null, null, null, null, "FI041", null, null, null, null); // 차입기관
      break;

    //유형 : 데이터영역
    case '1-1':
      sCmdName = "retrieveNonledgerAsetPatternCdInfo";
      udc_nonledgerAset.setSelectId(sCmdName);
      udc_nonledgerAset.cfCommonPopUp(scwin.udc_nonledgerAset_callbackfunc, code, name, sPopupCls, null, null, null, null, "FI041", null, null, null, null); // 차입기관
      break;

    //사원 : 조회영역
    case '2':
      sCmdName = "retrieveAcEmpInfo";
      pWhere = ed_coCd.getValue() + "," + scwin.txtCoClsCd;
      udc_drawEmpNo.setSelectId(sCmdName);
      udc_drawEmpNo.cfCommonPopUp(scwin.udc_drawEmpNo_callbackfunc, code, name, sPopupCls, null, null, null, null, pWhere, null, null, null, null);
      break;

    //사용부서 1 : 조회영역
    case '3':
      sCmdName = "retrieveAcctDeptCdInfo6";
      pWhere = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd;
      udc_srchacqDeptCdSt.setSelectId(sCmdName);
      udc_srchacqDeptCdSt.cfCommonPopUp(scwin.udc_srchacqDeptCdSt_callbackfunc, code, name, sPopupCls, null, null, null, null, pWhere, null, null, null, null);
      break;

    //사용부서 : 데이터영역
    case '3-1':
      sCmdName = "retrieveAcctDeptCdInfo6";
      pWhere = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd;
      udc_acqDeptCd.setSelectId(sCmdName);
      udc_acqDeptCd.cfCommonPopUp(scwin.udc_acqDeptCd_callbackfunc, code, name, sPopupCls, null, null, null, null, pWhere, null, null, null, null);
      break;

    //사용부서 2
    case '4':
      sCmdName = "retrieveAcctDeptCdInfo6";
      pWhere = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd;
      udc_srchacqDeptCdEnd.setSelectId(sCmdName);
      udc_srchacqDeptCdEnd.cfCommonPopUp(scwin.udc_srchacqDeptCdEnd_callbackfunc, code, name, sPopupCls, null, null, null, null, pWhere, null, null, null, null);
      break;

    // 처리계정
    case '5':
      sCmdName = "retrieveAcctCdInfo";
      udc_procAcct.setSelectId(sCmdName);
      udc_procAcct.cfCommonPopUp(scwin.udc_procAcct_callbackfunc, code, name, sPopupCls, null, null, null, null, null, null, null, null, null, null, null, null, null); // 요청자
      break;
  }
};
