scwin.ds_asetNo_onrowpositionchange = function (info) {
  if (scwin.isAdoption) {
    return;
  }
  let row = info.newRowIndex;
  let vCountRow = ds_asetNo.getRowCount();
  let vChgCount = 0;
  let vChgRow = 0;
  for (let i = 0; i < vCountRow; i++) {
    let vCurRowStatus = ds_asetNo.getRowStatus(i);
    if (vCurRowStatus == "C" || vCurRowStatus == "U") {
      vChgCount++;
      vChgRow = i;
      break; //신규 신규 만들면 우리는 처리상 이걸 한번 더 탄다. 그러면  row != vChgRow 안걸림
    }
  }
  if (vChgCount > 0 && row != vChgRow) {
    //$c.win.alert("부외자산관리 신규등록이나 변경사항을 저장하신 후에 다른 정보로 이동하실수 있습니다.");
    //ds_asetNo.setRowPosition(vChgRow);
    //gr_asetNo.setFocusedCell(vChgRow, 0, false);
    //console.log(vChgRow);

    for (let i = vCountRow - 1; i > -1; i--) {
      let vCurRowStatus = ds_asetNo.getRowStatus(i);
      if (vCurRowStatus == "U") {
        if (i != vChgRow) {
          ds_asetNo.undoRow(i);
        }
      } else if (vCurRowStatus == "C") {
        if (i != vChgRow) {
          ds_asetNo.removeRow(i);
        }
      }
    }

    //cfDisableBtnOnly([ btn_Trans, btn_Dis, btn_Add ]);
    //cfEnableBtnOnly([ btn_Upt, btn_Cancel ]); 

    //cfDisableBtnOnly([ btn_Upt, btn_Cancel ]);
    //cfEnableBtnOnly([ btn_Trans, btn_Dis, btn_Add, bAdd ]);
    return false;
  }

  // 편집 중인 행으로 돌아온 경우 입력 상태 유지
  if (vChgCount > 0 && row == vChgRow) {
    return;
  }
  $c.gus.cfDisableKeyData($p);
  ed_acqDeptCd.options.hidVal = ds_asetNo.getCellData(row, "acqDeptCd");
  ed_procAcct.options.hidVal = ds_asetNo.getCellData(row, "acctCd");
  scwin.txt_orgTransferDt = ds_asetNo.getCellData(row, "orgTransferDt");
};
scwin.ds_asetNo_onbeforerowpositionchange = async function (info) {
  let oldRowIndex = info.oldRowIndex;
  //let newRowIndex = info.newRowIndex;

  if (scwin.isSave == true || scwin.isAdoption == true) {
    return true;
  }

  //let newStatus = ds_asetNo.getRowStatus(newRowIndex);
  let oldStatus = ds_asetNo.getRowStatus(oldRowIndex);
  if (oldStatus == "C" || oldStatus == "U") {
    //console.log("oldRowIndex : " + oldRowIndex + ", newRowIndex : " + newRowIndex + ", data" + JSON.stringify(ds_asetNo.getAllJSON()));
    await $c.win.alert($p, "부외자산관리 신규등록이나 변경사항을 저장하신 후에 다른 정보로 이동하실수 있습니다.");
    ds_asetNo.setRowPosition(oldRowIndex, false);
    gr_asetNo.setFocusedCell(oldRowIndex, 0, false);
    return false;
  }
};

