//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  //alert(ds_asetNo.NameValue(ds_asetNo.RowPosition, "useYn"));
  //alert(ds_asetNo.getValue);   	
  //변경한 데이터가 있는지 체크한다. 
  if (ds_asetNo.getModifiedIndex().length < 1) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, Array("데이타"));
    return;
  }
  let rowPosi = ds_asetNo.getRowPosition();
  let ret;
  ds_asetNo.setCellData(rowPosi, "saveType", scwin.txt_saveType);
  let orgTransferDt = scwin.txt_orgTransferDt;

  // 이관시 사용부서 변경 여부 
  if (scwin.txt_saveType == "2") {
    let org_dep = ds_asetNo.getOriginalCellData(rowPosi, "acqDeptCd");
    var new_dep = ds_asetNo.getCellData(rowPosi, "acqDeptCd");
    if (org_dep == new_dep) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, Array("사용부서"));
      return;
    }
    ret = await $c.gus.cfIsAfterDate($p, ed_acqDt.getValue(), ed_transDt.getValue(), true);
    if (!ret) {
      $c.gus.cfAlertMsg($p, "이관일자는 취득일자 보다 이후 날짜 이어야 합니다.");
      ed_transDt.focus();
      return;
    }
    ret = await $c.gus.cfIsAfterDate($p, orgTransferDt, ed_transDt.getValue(), true);
    if (!ret) {
      $c.gus.cfAlertMsg($p, "새로운 이관일자는 이전 이관일자 보다 이후 날짜 이어야 합니다.");
      ed_transDt.focus();
      return;
    }
  } else if (scwin.txt_saveType == "1") {
    ret = await $c.gus.cfIsAfterDate($p, orgTransferDt, ed_disuseDt.getValue(), true);
    if (!ret) {
      $c.gus.cfAlertMsg($p, "폐기일자는 이관일자 보다 이후 날짜 이어야 합니다.");
      ed_disuseDt.focus();
      return;
    }
    ret = await $c.gus.cfIsAfterDate($p, ed_acqDt.getValue(), ed_disuseDt.getValue(), true);
    if (!ret) {
      $c.gus.cfAlertMsg($p, "폐기일자는 취득일자 보다 이후 날짜 이어야 합니다.");
      ed_disuseDt.focus();
      return;
    }
  }

  // 체크
  ret = await scwin.f_Validation();
  if (!ret) return;
  ret = await $c.win.confirm($p, "저장하시겠습니까?");
  if (ret == true) {
    scwin.isSave = true;
    //tr_saveAsetNo.post();
    $c.sbm.execute($p, sbm_saveAsetNo);
    scwin.isSave = false;
  }
};

